# Agents conversationnels + regle de routage PM (deterministe).
# Chaque agent augmente l'etat et retourne une entree de journal.


def agent_extractor(state):
    """Extrait les arguments et les ajoute a l'etat."""
    state["arguments"] = extract_arguments(state["text"])
    return state, {"agent": "extractor", "action": "extraction",
                   "result_count": len(state["arguments"])}


def agent_fallacy_checker(state):
    """Detecte les sophismes sur les arguments deja extraits."""
    state["fallacies"] = detect_fallacies(state.get("arguments", []))
    return state, {"agent": "fallacy_checker", "action": "detection",
                   "result_count": len(state["fallacies"])}


def agent_synthesizer(state):
    """Synthetise le rapport a partir des arguments et sophismes."""
    state["report"] = synthesize_report(
        state.get("arguments", []),
        state.get("fallacies", []),
    )
    return state, {"agent": "synthesizer", "action": "synthesis",
                   "result_count": 1}


# Registre des agents (nom -> callable).
AGENTS = {
    "extractor": agent_extractor,
    "fallacy_checker": agent_fallacy_checker,
    "synthesizer": agent_synthesizer,
}


def pm_route(state):
    """Regle de routage deterministe du Project Manager (substitut du LLM).

    Logique : on remplit les champs dans l'ordre, du plus fondamental au plus derive.
    Retourne le nom du prochain agent, ou None si l'etat est "complet".
    """
    if "arguments" not in state:
        return "extractor"
    if "fallacies" not in state:
        return "fallacy_checker"
    if "report" not in state:
        return "synthesizer"
    return None  # converge : tous les champs sont presents


print("--- Registre conversationnel ---")
print(f"Agents disponibles : {list(AGENTS.keys())}")
print("Regle PM           : extractor -> fallacy_checker -> synthesizer -> (stop)")

# M1 : detecteur de sophismes par lexique (rung 1 style).
FALLACY_KEYWORDS = {
    "appel_autorite": ["directeur", "valide cette", "forcement bonne"],
    "ad_hominem": ["comprennent rien", "semer le trouble"],
    "generalisation_hative": ["tout le monde sait", "tout le monde"],
    "appel_peur": ["catastrophe", "certaine"],
    "appel_conformite": ["tous les autres", "faire de meme"],
}


def m1_keyword_detector(sentences):
    findings = []
    fid = 1
    for idx, s in enumerate(sentences):
        s_low = s.lower()
        for family, kws in FALLACY_KEYWORDS.items():
            for kw in kws:
                if kw in s_low:
                    findings.append({
                        "method": "M1_keyword",
                        "artifact_id": f"fall_{fid}",
                        "kind": "sophisme",
                        "family": family,
                        "evidence": kw,
                        "sentence_index": idx,
                    })
                    fid += 1
                    break  # une famille par (phrase, match principal)
    return findings


m1_results = m1_keyword_detector(SENTENCES)
print(f"M1 : {len(m1_results)} findings")
for f in m1_results:
    print(f"  S{f['sentence_index']+1} [{f['family']}] evidence='{f['evidence']}' ({f['artifact_id']})")

# Smoke test : les 3 methodes tournent et produisent des findings sur le MEME texte.
METHODS = {"M1_keyword": m1_results, "M2_structural": m2_results, "M3_absolutism": m3_results}
total = sum(len(v) for v in METHODS.values())
print(f"Total findings (3 methodes) : {total}")
for name, findings in METHODS.items():
    print(f"  {name}: {len(findings)}")

from itertools import chain, combinations


class AF:
    """Cadre d'argumentation abstrait de Dung : <args, attacks>."""

    def __init__(self, args, attacks):
        self.args = set(args)
        self.attacks = set(attacks)  # ensemble de couples (attaquant, attaque)

    def attackers(self, x):
        """Arguments qui attaquent directement x."""
        return {a for (a, b) in self.attacks if b == x}

    def __repr__(self):
        att = ", ".join(f"{a}->{b}" for (a, b) in sorted(self.attacks))
        return f"AF(args={sorted(self.args)}, attacks=[{att}])"


# Un petit exemple ludique pour démarrer : a et b s'attaquent mutuellement.
af0 = AF({"a", "b"}, {("a", "b"), ("b", "a")})
print(af0)
print("Attaquants de a :", af0.attackers("a"))

def is_conflict_free(af, S):
    """True si aucun argument de S n'en attaque un autre dans S."""
    S = set(S)
    for (a, b) in af.attacks:
        if a in S and b in S:
            return False
    return True


print("a,b se battent -> {a,b} sans conflit ?", is_conflict_free(af0, {"a", "b"}))
print("{a} seul  -> sans conflit ?", is_conflict_free(af0, {"a"}))

def defeats(af, S, x):
    """True si S défait x (au moins un membre de S attaque x)."""
    return any((a, x) in af.attacks for a in S)


def defends(af, S, x):
    """True si S défend x : tout attaquant de x est défait par S."""
    return all(defeats(af, S, b) for b in af.attackers(x))


print("Dans af0, {a} défend-il a ?", defends(af0, {"a"}, "a"))
print("  (a est attaqué par b ; {a} défait-il b ? a->b :", ("a", "b") in af0.attacks, ")")

def is_admissible(af, S):
    """True si S est admissible : sans conflit et chacun de ses membres est défendu."""
    S = set(S)
    if not is_conflict_free(af, S):
        return False
    return all(defends(af, S, a) for a in S)


for cand in [set(), {"a"}, {"b"}, {"a", "b"}]:
    print(f"{{{' '.join(sorted(cand)) or '∅'}}} admissible ? {is_admissible(af0, cand)}")

def powerset(args):
    """Tous les sous-ensembles de args, par taille croissante."""
    args = list(args)
    return list(chain.from_iterable(
        combinations(args, r) for r in range(len(args) + 1)
    ))


def grounded(af):
    """Extension grounded : point fixe à partir de l'ensemble vide.

    On ajoute itérativement tout argument défendu par l'ensemble courant, jusqu'à
    ce qu'aucun ajout ne soit plus possible. Le résultat est unique (théorème de Dung).
    """
    S = set()
    changed = True
    while changed:
        changed = False
        for x in af.args:
            if x not in S and defends(af, S, x):
                S.add(x)
                changed = True
    return frozenset(S)


def preferred(af):
    """Extensions preferred : ensembles admissibles maximaux par inclusion."""
    adm = [frozenset(S) for S in powerset(af.args) if is_admissible(af, S)]
    # maximal : aucun autre admissible ne le contient strictement
    return [a for a in adm if not any(a < b for b in adm)]


def stable(af):
    """Extensions stables : admissibles qui défont tout argument hors de l'extension."""
    out = []
    for S in powerset(af.args):
        S = set(S)
        if is_admissible(af, S) and all(
            defeats(af, S, x) for x in af.args if x not in S
        ):
            out.append(frozenset(S))
    return out


def resume(af, label=""):
    """Calcule et affiche les trois sémantiques d'un AF."""
    g = grounded(af)
    p = preferred(af)
    s = stable(af)
    print(f"=== {label or af} ===")
    print(f"  grounded  : {{{', '.join(sorted(g)) or '∅'}}}   (unique, sceptique)")
    print(f"  preferred : {[sorted('{' + ','.join(sorted(e)) + '}') and '{' + ','.join(sorted(e)) + '}' for e in p]}   ({len(p)} ext., crédule)")
    if s:
        print(f"  stable    : {[ '{' + ','.join(sorted(e)) + '}' for e in s]}   ({len(s)} ext.)")
    else:
        print(f"  stable    : AUCUNE (pas d'extension stable)")
    print()
    return g, p, s

