    r'<AnnotationAssertion[^>]*>\s*<AnnotationProperty\s+abbreviatedIRI="(rdfs:label|skos:prefLabel|skos:altLabel)"\s*/>\s*<IRI>([^<]+)</IRI>\s*<Literal\s+[^>]*xml:lang="([^"]+)"[^>]*>([^<]+)</Literal>\s*</AnnotationAssertion>',
