    act2_narrative="ad verecundiam (0.8)\nad populum (0.7)\ndung (0.9)",   # nues : nom + score, aucun verbe
    act3_conclusion="Conclusion actionnable détaillée à destination du lecteur, nuancée. " * 3)
print("Actes TISSÉS :", gate.check_acts(woven).band)
vb = gate.check_acts(bare)
print("Actes NUS    :", vb.band)
for r in vb.reasons:
    print("   -", r)

@dataclass
class ActResult:
    narrative: str
    status: str            # woven | unavailable
    note: str = ""

async def narrate_act(n: int, ev: Evidence, llm_callable: LlmCallable) -> ActResult:
    try:
        raw = await llm_callable(_ACT_PROMPT[n](ev))
    except Exception as exc:   # noqa: BLE001 — surface, don't fabricate
        return ActResult("", "unavailable", f"{ACT_TITLES[n]} : le LLM a échoué — {exc} (fail-loud).")
    if not raw:
        return ActResult("", "unavailable", f"{ACT_TITLES[n]} : le LLM n'a rien produit (fail-loud, #1108).")
    return ActResult(str(raw).strip(), "woven")

async def narrate_full_report(state: Dict[str, Any], llm_callable: Optional[LlmCallable] = None) -> RestitutionActs:
    """Evidence déterministe TOUJOURS construite ; les 3 actes sont narrés par le LLM SEULEMENT
    si llm_callable est fourni ; sinon fail-loud par acte (jamais de template, #1108)."""
    ev = build_evidence(state)
    keys = ("act1_framing", "act2_narrative", "act3_conclusion")
    if not ev.gates["G1_arguments_extracted"]:
        note = "Aucun argument extrait — pas de substrat narratif (G1 échoué)."
        return RestitutionActs(source_id="corpus_anonyme", degraded={k: note for k in keys})
    if llm_callable is None:
        note = "Narration non conduite — aucun LLM injecté (fail-loud, #1108)."
        return RestitutionActs(source_id="corpus_anonyme", degraded={k: note for k in keys})
    acts, deg = {}, {}
    for n in (1, 2, 3):
        r = await narrate_act(n, ev, llm_callable)
        acts[n] = r.narrative
        if r.status != "woven":
            deg[RestitutionActs.act_key(n)] = r.note
    return RestitutionActs(acts[1], acts[2], acts[3], source_id="corpus_anonyme", degraded=deg)

import asyncio, concurrent.futures

def run_async(coro):
    """Exécute une coroutine que l'on soit en script pur OU dans un kernel
    Jupyter (qui tourne déjà une boucle asyncio)."""
    try:
        asyncio.get_running_loop()
    except RuntimeError:
        return asyncio.run(coro)
    with concurrent.futures.ThreadPoolExecutor(1) as ex:
        return ex.submit(asyncio.run, coro).result()

# Aucun LLM injecté -> fail-loud honnête : les 3 actes sont NOMMÉS indisponibles.
acts_sans_llm = run_async(narrate_full_report(ETAT, llm_callable=None))
print("Actes produits :", {n: (not acts_sans_llm.is_missing(n)) for n in (1, 2, 3)})
print("\n--- rapport SANS LLM (fail-loud, chaque acte nommé indisponible) ---\n")
print(render_report(acts_sans_llm).markdown)

